import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import '@fortawesome/fontawesome-free/css/all.min.css';

const Register = () => {
  const [formData, setFormData] = useState({
    Username: '',
    Password: '',
    ClientCode: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const validatePassword = (password) => {
    const errors = [];
    if (!/[A-Z]/.test(password)) {
      errors.push("Password must have at least one uppercase letter ('A'-'Z')");
    }
    if (!/[0-9]/.test(password)) {
      errors.push("Password must have at least one digit ('0'-'9')");
    }
    if (!/[^A-Za-z0-9]/.test(password)) {
      errors.push("Password must have at least one non-alphanumeric character");
    }
    return errors;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const passwordErrors = validatePassword(formData.Password);
    if (passwordErrors.length > 0) {
      setError(passwordErrors.join('\n'));
      setLoading(false);
      return;
    }
    try {
      await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthRegister', formData);
      toast.success('Registration successful! Please login.', {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
      navigate('/login');
    } catch (err) {
      const errorMessage = err.response?.data || 'Registration failed. Please try again.';
      setError(Array.isArray(errorMessage) ? errorMessage.map(e => e.Description).join('\n') : errorMessage);
      toast.error('Registration failed. Please check the requirements.', {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #43cea2 0%, #185a9d 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif'
    }}>
      <ToastContainer />
      <div style={{
        minWidth: 350,
        maxWidth: 420,
        width: '100%',
        background: 'rgba(255, 255, 255, 0.95)',
        borderRadius: 20,
        boxShadow: '0 8px 32px 0 rgba(24, 90, 157, 0.2)',
        backdropFilter: 'blur(10px)',
        border: '1px solid rgba(255, 255, 255, 0.18)',
        padding: '2.8rem 2.5rem',
        margin: '2rem 0'
      }}>
        <div className="text-center mb-4">
          <div style={{ 
            fontSize: '2.5rem', 
            marginBottom: '0.5rem',
            background: 'linear-gradient(45deg, #43cea2, #185a9d)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent'
          }}>
            <i className="fas fa-user-plus"></i>
          </div>
          <h3 className="mb-1 fw-bold" style={{ 
            fontSize: '1.6rem', 
            color: '#333',
            textAlign: 'center', 
            letterSpacing: 0.5
          }}>Create Account</h3>
          <p style={{ color: '#666', fontSize: '0.95rem' }}>Register to access the RFID API Dashboard</p>
        </div>

        {error && (
          <div className="alert alert-danger py-2" style={{ 
            fontSize: '0.98rem',
            borderRadius: '10px',
            border: 'none',
            background: 'rgba(220, 53, 69, 0.1)',
            color: '#dc3545'
          }}>{error}</div>
        )}
        
        <form onSubmit={handleSubmit} autoComplete="off">
          <div className="mb-3">
            <label htmlFor="Username" className="form-label" style={{ 
              fontWeight: 600, 
              color: '#555',
              fontSize: '0.9rem',
              marginBottom: '0.4rem'
            }}>
              <i className="fas fa-user me-2 text-success"></i>Username
            </label>
            <input
              type="text"
              className="form-control"
              id="Username"
              name="Username"
              value={formData.Username}
              onChange={handleChange}
              required
              placeholder="Enter your email or username"
              style={{ 
                fontSize: '1.05rem', 
                background: 'rgba(255, 255, 255, 0.8)', 
                border: '1px solid #e0e0e0', 
                borderRadius: 12,
                padding: '0.6rem 1rem',
                transition: 'all 0.3s',
                boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
              }}
            />
          </div>
          
          <div className="mb-3">
            <label htmlFor="ClientCode" className="form-label" style={{ 
              fontWeight: 600, 
              color: '#555',
              fontSize: '0.9rem',
              marginBottom: '0.4rem'
            }}>
              <i className="fas fa-building me-2 text-info"></i>Client Code
            </label>
            <input
              type="text"
              className="form-control"
              id="ClientCode"
              name="ClientCode"
              value={formData.ClientCode}
              onChange={handleChange}
              required
              placeholder="Enter your client code"
              style={{ 
                fontSize: '1.05rem', 
                background: 'rgba(255, 255, 255, 0.8)', 
                border: '1px solid #e0e0e0', 
                borderRadius: 12,
                padding: '0.6rem 1rem',
                transition: 'all 0.3s',
                boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
              }}
            />
          </div>
          
          <div className="mb-4">
            <label htmlFor="Password" className="form-label" style={{ 
              fontWeight: 600, 
              color: '#555',
              fontSize: '0.9rem',
              marginBottom: '0.4rem'
            }}>
              <i className="fas fa-lock me-2 text-warning"></i>Password
            </label>
            <input
              type="password"
              className="form-control"
              id="Password"
              name="Password"
              value={formData.Password}
              onChange={handleChange}
              required
              placeholder="Create a strong password"
              style={{ 
                fontSize: '1.05rem', 
                background: 'rgba(255, 255, 255, 0.8)', 
                border: '1px solid #e0e0e0', 
                borderRadius: 12,
                padding: '0.6rem 1rem',
                transition: 'all 0.3s',
                boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
              }}
            />
            <small className="text-muted mt-2" style={{ display: 'block', backgroundColor: 'rgba(0,0,0,0.03)', padding: '10px', borderRadius: '8px', marginTop: '8px' }}>
              <i className="fas fa-shield-alt me-1 text-success"></i>
              Password must contain:
              <ul className="mb-0 mt-1" style={{ paddingLeft: '1.5rem' }}>
                <li>At least one uppercase letter</li>
                <li>At least one number</li>
                <li>At least one special character</li>
              </ul>
            </small>
          </div>
          
          <button
            type="submit"
            className="btn w-100 fw-bold"
            style={{
              fontSize: '1.1rem',
              background: 'linear-gradient(45deg, #185a9d, #43cea2)',
              color: '#fff',
              border: 'none',
              borderRadius: 12,
              padding: '0.7rem',
              marginTop: 8,
              marginBottom: 12,
              boxShadow: '0 4px 10px rgba(24, 90, 157, 0.3)',
              transition: 'all 0.3s'
            }}
            disabled={loading}
            onMouseOver={(e) => {
              e.currentTarget.style.background = 'linear-gradient(45deg, #154d84, #37b389)';
              e.currentTarget.style.transform = 'translateY(-2px)';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.background = 'linear-gradient(45deg, #185a9d, #43cea2)';
              e.currentTarget.style.transform = 'translateY(0)';
            }}
          >
            {loading ? (
              <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
            ) : (
              <>
                <i className="fas fa-user-plus me-2"></i>
                Create Account
              </>
            )}
          </button>
        </form>
        
        <div className="text-center mt-4" style={{ fontSize: '0.98rem', color: '#555' }}>
          Already have an account?{' '}
          <span
            className="fw-bold"
            style={{ 
              color: '#185a9d', 
              cursor: 'pointer',
              textDecoration: 'underline',
              transition: 'all 0.3s'
            }}
            onClick={() => navigate('/login')}
          >
            Log in now
          </span>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
